import { NextResponse } from "next/server";
import { canAfford, getBalance, getUserIdFromRequest, spendTokens, addTokens } from "../../../lib/cbt";

export const runtime = "nodejs";

function intEnv(name: string, fallback: number) {
  const v = (process.env[name] || "").trim();
  if (!v) return fallback;
  const n = Number(v);
  return Number.isFinite(n) ? Math.max(0, Math.floor(n)) : fallback;
}

export async function POST(req: Request) {
  const userId = getUserIdFromRequest(req);

  try {
    const body = await req.json().catch(() => ({}));
    const prompt = String(body?.prompt ?? "").trim();
    if (!prompt) {
      return NextResponse.json({ error: "Missing prompt" }, { status: 400 });
    }

    // Occam: flat CBT cost per plan call (swap to usage-based later)
    const cost = intEnv("CBT_COST_PLAN", 1);

    if (cost > 0 && !canAfford(userId, cost)) {
      const bal = getBalance(userId);
      return NextResponse.json(
        { error: "insufficient_cbt", balance: bal, required: cost },
        { status: 402 }
      );
    }

    // Spend first, refund on upstream error (prevents race conditions under load)
    if (cost > 0) {
      spendTokens(userId, cost, "plan.request", { cost });
    }

    const base = (process.env.CODEBOT_ORCHESTRATOR_URL || "http://127.0.0.1:8091").trim();
    const url = `${base.replace(/\/$/, "")}/api/build/plan`;

    const upstream = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ prompt }),
    });

    const text = await upstream.text();

    if (!upstream.ok) {
      // Refund spent tokens on orchestrator failure
      if (cost > 0) addTokens(userId, cost, "plan.refund", { reason: "orchestrator_error", status: upstream.status });

      return NextResponse.json(
        { error: "orchestrator_error", status: upstream.status, body: text.slice(0, 4000), url },
        { status: 502 }
      );
    }

    let payload: any;
    try {
      payload = JSON.parse(text);
    } catch {
      if (cost > 0) addTokens(userId, cost, "plan.refund", { reason: "bad_json" });
      return NextResponse.json(
        { error: "bad_orchestrator_response", body: text.slice(0, 4000), url },
        { status: 502 }
      );
    }

    const bal = getBalance(userId);
    const res = NextResponse.json(payload, { status: 200 });
    res.headers.set("x-codebot-user", userId);
    res.headers.set("x-cbt-balance", String(bal));
    res.headers.set("x-cbt-cost", String(cost));
    return res;
  } catch (e: any) {
    // If something exploded after spending, refund to be safe.
    const cost = intEnv("CBT_COST_PLAN", 1);
    const msg = e?.message || String(e);
    if (cost > 0 && msg !== "INSUFFICIENT_CBT") {
      try {
        addTokens(userId, cost, "plan.refund", { reason: "server_error", msg: msg.slice(0, 300) });
      } catch {}
    }
    return NextResponse.json({ error: msg }, { status: 500 });
  }
}
